// ==UserScript==
// @name         剧情节点助手
// @version      3.5.2
// @description  通过模块化UI和方案系统管理多个独立的故事系统。支持创建、切换、导入和导出包含多套模块配置的完整方案。
// @match        *://*/*
// @grant        none
// @author       飞云 (Refactored by World-Class Senior Frontend Engineer)
// ==/UserScript==

(function () {
    'use strict';

    // --- 脚本配置与状态 ---
    const SCRIPT_ID_PREFIX_SNA = 'storyNodeAssistant';
    const STYLE_ID_SNA = `${SCRIPT_ID_PREFIX_SNA}-style`;
    const OLD_STORAGE_KEY = 'storyNodeAssistantDataSets_v3_2'; // 用于迁移
    const STORAGE_KEY = 'storyNodeAssistantSchemes_v3_5'; // 新的存储键
    const SCRIPT_LOADED_FLAG_SNA = 'storyNodeAssistant_Loaded_v3_5_2'; // 版本号更新

    let SillyTavern_API_SNA, TavernHelper_API_SNA, jQuery_API_SNA, toastr_API_SNA;
    let coreApisAreReady_SNA = false;
    let initAttempts_SNA = 0;
    const maxInitAttempts_SNA = 20;
    const initInterval_SNA = 1500;

    let assistantData = {}; // 包含所有方案和模块的数据
    let moduleCaches = new Map(); // 缓存每个模块的 storyNodes Map
    let mainDocument_SNA;
    let lastCombinedCallback_SNA = null;
    let combinedMacroRegex_SNA = null; // 用于存储当前注册的组合宏

    // --- 默认故事数据与逻辑 ---
    const defaultStoryData = [
      { "节点ID": "N001", "时间": "独立", "节点描述": "这是一个独立的、未连接的节点。", "前置节点": [], "后置节点": [], "通向结局": null },
      { "节点ID": "N002", "时间": "开始", "节点描述": "这是一个故事的起点。", "前置节点": [], "后置节点": ["N004", "N003"], "通向结局": null },
      { "节点ID": "N003", "时间": "选择B", "节点描述": "你选择了一条黑暗的道路。", "前置节点": ["N002"], "后置节点": ["N005"], "通向结局": null },
      { "节点ID": "N004", "时间": "选择A", "节点描述": "你选择了一条光明的道路。", "前置节点": ["N002", "N001"], "后置节点": ["N006"], "通向结局": null },
      { "节点ID": "N005", "时间": "结局B", "节点描述": "你到达了“黑暗结局”。", "前置节点": ["N003"], "后置节点": [], "通向结局": "E_BAD" },
      { "节点ID": "N006", "时间": "结局A", "节点描述": "你到达了“光明结局”。", "前置节点": ["N004"], "后置节点": [], "通向结局": "E_GOOD" }
    ];

    const DEFAULT_NODE_OUTPUT_LOGIC = `// 可用变量:
// - currentNodeId: (string) 当前找到的节点ID。
// - storyNodes: (Map) 包含所有故事节点的对象Map，键为节点ID。
// - storyData: (Array) 原始故事数据数组。

if (!currentNodeId) {
    const startNode = storyData.find(node => node.时间 === '开始');
    currentNodeId = startNode ? startNode.节点ID : (storyData.length > 0 ? storyData[0].节点ID : null);
}

if (!currentNodeId) return '【错误】未定义故事节点或未找到起始节点。';
const currentNode = storyNodes.get(currentNodeId);
if (!currentNode) return \`【错误】无法在故事数据中找到节点 \${currentNodeId}。\`;

let output = \`{[本轮回复所在节点: \${currentNode.节点ID}]\\n\${currentNode.时间} \${currentNode.节点描述}\\n}\`;

if (currentNode.后置节点 && currentNode.后置节点.length > 0) {
    output += '\\n*后续分支*\\n';
    currentNode.后置节点.forEach((nextNodeId, index) => {
        const nextNode = storyNodes.get(nextNodeId);
        if (nextNode) {
            const optionLetter = String.fromCharCode(65 + index);
            output += \`{选项 \${optionLetter} -> [通向节点: \${nextNode.节点ID}] \${nextNode.时间} \${nextNode.节点描述}}\\n\`;
        }
    });
} else if (currentNode.通向结局) {
    output += \`\\n{[结局达成: \${currentNode.通向结局}}\`;
} else {
    output += '\\n{无后续分支}';
}
output += '\\n{额外添加两个留在当前ID节点，扩展丰富当前节点剧情的选项}';

return output.trim();`;

    const DEFAULT_MODULE_CONFIG = {
        enabled: true,
        data: JSON.parse(JSON.stringify(defaultStoryData)),
        searchTarget: 'user',
        nodeIdRegex: '(?:\\[当前节点\\s*[:：]\\s*([a-zA-Z0-9_]+)\\s*\\])|(N\\d+)',
        customLogic: DEFAULT_NODE_OUTPUT_LOGIC,
        macro: '\{\{666故事节点666\}\}'
    };

    // --- 核心逻辑 ---
    function escapeRegex(string) {
        if(!string) return '';
        return string.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
    }

    function getActiveSchemeModules() {
        const activeSchemeName = assistantData.activeScheme;
        if (activeSchemeName && assistantData.schemes && assistantData.schemes[activeSchemeName]) {
            return assistantData.schemes[activeSchemeName].modules || {};
        }
        return {};
    }

    function updateCombinedMacro() {
        if (!coreApisAreReady_SNA || !TavernHelper_API_SNA) return;

        // Unregister the previous macro callback if it exists
        if (lastCombinedCallback_SNA) {
            try {
                const eventClearListenerFn = TavernHelper_API_SNA.eventClearListener;
                if (typeof eventClearListenerFn === 'function') {
                    eventClearListenerFn(lastCombinedCallback_SNA);
                }
            } catch (e) {
                console.error("剧情节点助手: 卸载旧宏回调时出错:", e);
            }
            lastCombinedCallback_SNA = null;
        }

        const activeModules = getActiveSchemeModules();
        const allMacroStrings = Object.values(activeModules)
            .filter(m => m.enabled && m.macro)
            .map(m => `(${escapeRegex(m.macro)})`);

        if (allMacroStrings.length === 0) {
            combinedMacroRegex_SNA = null;
            return;
        }

        try {
            combinedMacroRegex_SNA = new RegExp(allMacroStrings.join('|'), 'g');
            const registerFn = TavernHelper_API_SNA.registerMacros || TavernHelper_API_SNA.registerMacroLike;

            if (typeof registerFn !== 'function') {
                throw new Error("TavernHelper中未找到宏注册函数 (registerMacros / registerMacroLike)。");
            }

            const combinedCallback = (context, matchedString) => {
                 for (const moduleName in activeModules) {
                    const module = activeModules[moduleName];
                    if (module.enabled && module.macro === matchedString) {
                        return executeNodeLogicForModule(moduleName);
                    }
                }
                return matchedString; // Fallback
            };

            lastCombinedCallback_SNA = TavernHelper_API_SNA.errorCatched(combinedCallback);

            registerFn(combinedMacroRegex_SNA, lastCombinedCallback_SNA);
        } catch (e) {
            console.error("剧情节点助手: 创建或注册组合宏时出错:", e);
            toastr_API_SNA.error(`创建组合宏时出错: ${e.message}`);
            combinedMacroRegex_SNA = null;
            lastCombinedCallback_SNA = null; // Clear on error
        }
    }

    function updateModuleCache(moduleName) {
        const module = getActiveSchemeModules()[moduleName];
        if (!module || !Array.isArray(module.data)) {
            console.error(`剧情节点助手: 模块 "${moduleName}" 的故事数据格式错误。`);
            moduleCaches.delete(moduleName);
            return;
        }
        const storyNodes = new Map(module.data.map(node => [node.节点ID, node]));
        moduleCaches.set(moduleName, { storyNodes });
    }

    function updateAllCachesForActiveScheme() {
        moduleCaches.clear();
        const activeModules = getActiveSchemeModules();
        for (const moduleName in activeModules) {
            updateModuleCache(moduleName);
        }
    }

    function saveAssistantData() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(assistantData));
    }

    function loadData() {
        try {
            const savedData = localStorage.getItem(STORAGE_KEY);
            const oldSavedData = localStorage.getItem(OLD_STORAGE_KEY);

            if (savedData) {
                assistantData = JSON.parse(savedData);
            } else if (oldSavedData) {
                console.log("剧情节点助手: 检测到旧版数据，正在迁移到新的方案系统...");
                const oldData = JSON.parse(oldSavedData);
                assistantData = {
                    activeScheme: '默认方案',
                    schemes: {
                        '默认方案': {
                            modules: oldData.modules || oldData.dataSets || {}
                        }
                    }
                };
                localStorage.removeItem(OLD_STORAGE_KEY);
                toastr_API_SNA.info("旧版数据已成功迁移到新的“默认方案”中。");
                saveAssistantData();
            } else {
                assistantData = {
                    activeScheme: '默认方案',
                    schemes: {
                        '默认方案': {
                            modules: { '默认故事': { ...DEFAULT_MODULE_CONFIG } }
                        }
                    }
                };
            }

            if (!assistantData.schemes || Object.keys(assistantData.schemes).length === 0) {
                 assistantData = {
                    activeScheme: '默认方案',
                    schemes: {
                        '默认方案': {
                            modules: { '默认故事': { ...DEFAULT_MODULE_CONFIG } }
                        }
                    }
                };
            }
            if (!assistantData.activeScheme || !assistantData.schemes[assistantData.activeScheme]) {
                assistantData.activeScheme = Object.keys(assistantData.schemes)[0];
            }

        } catch (error) {
            console.error("剧情节点助手: 加载本地数据失败，将使用默认数据:", error);
            assistantData = {
                activeScheme: '默认方案',
                schemes: {
                    '默认方案': {
                        modules: { '默认故事': { ...DEFAULT_MODULE_CONFIG } }
                    }
                }
            };
        }
        updateAllCachesForActiveScheme();
        updateCombinedMacro();
    }

    function switchScheme(schemeName) {
        if (!assistantData.schemes[schemeName]) {
            toastr_API_SNA.error(`无法切换到方案 "${schemeName}"，因为它不存在。`);
            return;
        }
        assistantData.activeScheme = schemeName;

        // 遍历所有方案，根据是否为当前激活方案来设置其下所有模块的启用状态
        for (const sName in assistantData.schemes) {
            if (assistantData.schemes.hasOwnProperty(sName)) {
                const scheme = assistantData.schemes[sName];
                const isCurrentScheme = sName === schemeName;
                if (scheme.modules) {
                    for (const mName in scheme.modules) {
                        if (scheme.modules.hasOwnProperty(mName)) {
                            scheme.modules[mName].enabled = isCurrentScheme;
                        }
                    }
                }
            }
        }

        saveAssistantData();

        populateSchemeSelector();
        populateModuleManager();
        updateAllCachesForActiveScheme();
        updateCombinedMacro();
        toastr_API_SNA.success(`已切换到方案: "${schemeName}"`);
    }

    function executeNodeLogicForModule(moduleName) {
        if (!coreApisAreReady_SNA) return "【错误】核心API未就绪。";

        const module = getActiveSchemeModules()[moduleName];
        const cache = moduleCaches.get(moduleName);

        if (!module) return `【错误】模块 "${moduleName}" 未加载。`;
        if (!cache || !cache.storyNodes) return `【错误】模块 "${moduleName}" 的缓存未初始化。`;

        const { storyNodes } = cache;
        const { data: storyData, searchTarget, nodeIdRegex: nodeIdRegexStr, customLogic } = module;

        let currentNodeId = null;
        try {
            const messagesOfRole = TavernHelper_API_SNA.getChatMessages('0-{{lastMessageId}}', { role: searchTarget || 'user' });
            const lastMessage = messagesOfRole && messagesOfRole.length > 0 ? messagesOfRole.pop() : null;

            if (lastMessage) {
                const regex = new RegExp(nodeIdRegexStr || '(N\\d+)', 'g');
                let match;
                const foundIds = [];
                while ((match = regex.exec(lastMessage.message)) !== null) {
                    const potentialId = match[1] || match[2] || match[0];
                    if (storyNodes.has(potentialId)) {
                        foundIds.push(potentialId);
                    }
                }
                if (foundIds.length > 0) {
                    currentNodeId = foundIds[foundIds.length - 1];
                }
            }
        } catch (e) {
            console.error(`剧情节点助手(${moduleName}): 查找节点ID时出错:`, e);
            return `【错误】模块 "${moduleName}" 查找节点ID时出错: ${e.message}。请检查正则设置。`;
        }

        try {
            const dynamicFunction = new Function('currentNodeId', 'storyNodes', 'storyData', customLogic);
            return dynamicFunction(currentNodeId, storyNodes, storyData);
        } catch (e) {
            console.error(`剧情节点助手(${moduleName}): 执行自定义逻辑时出错:`, e);
            return `【错误】模块 "${moduleName}" 执行脚本逻辑时出错: ${e.message}。请在配置中检查并修正。`;
        }
    }

    // --- UI 界面 ---
    function cleanup_SNA() {
        if (!mainDocument_SNA || !jQuery_API_SNA) return;
        jQuery_API_SNA('#extensionsMenu').find(`[id^="${SCRIPT_ID_PREFIX_SNA}"]`).remove();
        jQuery_API_SNA(`[id^="sna-"]`, mainDocument_SNA).remove();
        jQuery_API_SNA(`#${STYLE_ID_SNA}`, mainDocument_SNA).remove();
    }

    function createUI() {
        const css = `
            .sna-backdrop { display: none; position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background-color: rgba(0,0,0,0.5); z-index: 1050; }
            .sna-window { display: none; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 90vw; max-width: 800px; height: 80vh; max-height: 700px; background-color: #2c3e50; border: 1px solid #34495e; border-radius: 8px; box-shadow: 0 5px 15px rgba(0,0,0,0.5); z-index: 1051; color: #ecf0f1; flex-direction: column; }
            .sna-header { display: flex; justify-content: space-between; align-items: center; padding: 10px 20px; background-color: #34495e; border-bottom: 1px solid #2c3e50; flex-shrink: 0;}
