            .sna-btn-danger:hover { background-color: #c0392b; }
            .sna-textarea { width: 100%; box-sizing: border-box; flex-grow: 1; background-color: #1e2a38; color: #ecf0f1; border: 1px solid #34495e; border-radius: 4px; padding: 10px; font-family: monospace; font-size: 14px; resize: none; }
