    function handleNewScheme() {
        let newName = prompt("请输入新方案的名称：");
        if (!newName) { toastr_API_SNA.info("创建已取消。"); return; }
        while (assistantData.schemes[newName]) {
            newName = prompt(`方案名称 "${newName}" 已存在。请输入一个新名称：`);
            if (!newName) { toastr_API_SNA.info("创建已取消。"); return; }
        }
        assistantData.schemes[newName] = { modules: {} };
        switchScheme(newName);
    }

    function handleDeleteScheme() {
        if (Object.keys(assistantData.schemes).length <= 1) {
            toastr_API_SNA.warning("不能删除最后一个方案。");
            return;
        }
        const schemeToDelete = assistantData.activeScheme;
        if (confirm(`你确定要删除方案 "${schemeToDelete}" 吗？此操作无法撤销。`)) {
            delete assistantData.schemes[schemeToDelete];
            const newActiveName = Object.keys(assistantData.schemes)[0];
            switchScheme(newActiveName);
            toastr_API_SNA.success(`方案 "${schemeToDelete}" 已被删除。`);
        }
    }

    function handleRenameScheme() {
        const oldName = assistantData.activeScheme;
        let newName = prompt(`请输入方案 "${oldName}" 的新名称：`, oldName);
        if (!newName || newName === oldName) { toastr_API_SNA.info("重命名已取消。"); return; }
        if (assistantData.schemes[newName]) {
            toastr_API_SNA.error(`方案名称 "${newName}" 已存在。`); return;
        }
        assistantData.schemes[newName] = assistantData.schemes[oldName];
        delete assistantData.schemes[oldName];
        switchScheme(newName);
    }

    function handleExportScheme() {
        const schemeToExport = assistantData.schemes[assistantData.activeScheme];
        const dataStr = JSON.stringify(schemeToExport, null, 2);
        const blob = new Blob([dataStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = mainDocument_SNA.createElement('a');
        a.href = url;
        a.download = `${assistantData.activeScheme.replace(/[\\/:"*?<>|]/g, '_')}.sna_scheme.json`;
        mainDocument_SNA.body.appendChild(a);
        a.click();
        mainDocument_SNA.body.removeChild(a);
        URL.revokeObjectURL(url);
        toastr_API_SNA.info(`方案 "${assistantData.activeScheme}" 已开始导出。`);
    }

    function handleImportScheme(event) {
        const file = event.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const importedScheme = JSON.parse(e.target.result);
                if (!importedScheme.modules || typeof importedScheme.modules !== 'object') throw new Error("导入的方案文件格式不正确，缺少 'modules' 对象。");

                let newName = prompt("请输入新方案的名称：", file.name.replace(/\.sna_scheme\.json$/, ''));
                if (!newName) { toastr_API_SNA.info("导入已取消。"); return; }
                while (assistantData.schemes[newName]) {
                    newName = prompt(`方案名称 "${newName}" 已存在。请输入一个新名称：`);
                    if (!newName) { toastr_API_SNA.info("导入已取消。"); return; }
                }

                assistantData.schemes[newName] = importedScheme;
                switchScheme(newName);
                toastr_API_SNA.success(`方案 "${newName}" 已成功导入并激活。`);

            } catch (error) {
                toastr_API_SNA.error(`方案导入失败：${error.message}`);
            } finally {
                event.target.value = '';
                event.target.onchange = null;
            }
        };
        reader.readAsText(file);
    }

