    function handleTestRun(event) {
        const window = mainDocument_SNA.getElementById('sna-config-editor-window');
        const moduleName = window.dataset.moduleName;
        const testNodeId = mainDocument_SNA.getElementById('sna-config-test-node-id').value;
        const logicToTest = mainDocument_SNA.getElementById('sna-config-logic-editor').value;
        const outputElement = mainDocument_SNA.getElementById('sna-config-test-output');

        const tempStoryData = getActiveSchemeModules()[moduleName].data;
        const tempStoryNodes = new Map(tempStoryData.map(node => [node.节点ID, node]));

        if (!testNodeId) {
            outputElement.textContent = '【测试错误】请输入一个要测试的节点ID。'; return;
        }
        if (!tempStoryNodes.has(testNodeId)) {
            outputElement.textContent = `【测试错误】节点ID "${testNodeId}" 在当前模块数据中不存在。`; return;
        }

        try {
            const dynamicFunction = new Function('currentNodeId', 'storyNodes', 'storyData', logicToTest);
            const result = dynamicFunction(testNodeId, tempStoryNodes, tempStoryData);
            outputElement.textContent = result;
        } catch (e) {
            console.error(`剧情节点助手(${moduleName}-测试): 执行自定义逻辑时出错:`, e);
            outputElement.textContent = `【测试错误】执行脚本逻辑时出错: ${e.message}`;
        }
    }

